      text: "...a financial construct far larger than the visible economy.",
      start_time_seconds: 3.5,
      end_time_seconds: 6.0,
    },
  ];

  // Timings (in frames)
  const startZoomFrame = Math.round(1.0 * fps); // 30
  const endZoomFrame = Math.round(3.5 * fps); // 105
  const startGlitchFrame = Math.round(3.5 * fps); // 105

  // Animations
  const zoomProgress = interpolate(
    frame,
    [startZoomFrame, endZoomFrame],
    [0, 1],
    {
      easing: Easing.out(Easing.exp),
      extrapolateRight: "clamp",
      extrapolateLeft: "clamp",
    }
  );

  // Camera is fixed at z=5. Group moves back to z=-28 to reveal the massive radius 12 sphere.
  const groupZ = interpolate(zoomProgress, [0, 1], [0, -28]);

  // Object A (Real Economy) fade in
  const opacityA = interpolate(frame, [0, 15], [0, 1], {
    extrapolateRight: "clamp",
  });

  // Object B (Shadow Bubble) opacity and glitch
  const baseOpacityB = interpolate(zoomProgress, [0, 0.5], [0, 0.15], {
    extrapolateRight: "clamp",
  });

  // Deterministic pulse for instability
  const pulseIntensity = interpolate(
    frame,
    [startGlitchFrame, startGlitchFrame + 15],
    [0, 1],
    { extrapolateRight: "clamp", extrapolateLeft: "clamp" }
  );
  const pulseValue = Math.sin(frame * 0.8) * 0.15;
  const opacityB = baseOpacityB + pulseValue * pulseIntensity;

  // Object B scale jitter during glitch phase
  const scaleJitter = pulseIntensity * (Math.sin(frame * 1.5) * 0.02);
  const scaleB = 1 + scaleJitter;

  // Number Counter Logic (Handling massive numbers safely)
  // Animate up to 17,000 (trillions), then append zeros to reach quadrillions
  const currentTrillions = Math.floor(
    interpolate(zoomProgress, [0, 1], [0, 17000])
  );
  const baseStr = currentTrillions.toString();
  const fullStr = currentTrillions === 0 ? "0" : baseStr + "000000000000";
  const formattedNumber = "$" + fullStr.replace(/\B(?=(\d{3})+(?!\d))/g, ",");

  const numberOpacity = interpolate(
    frame,
    [startZoomFrame, startZoomFrame + 15],
    [0, 1],
    { extrapolateRight: "clamp", extrapolateLeft: "clamp" }
