                clearcoat={0.5}
                transparent={true}
                opacity={opacityA}
              />
            </Sphere>

            {/* Object B: Shadow Banking Bubble (Wireframe, Fragile) */}
            <Sphere
              args={[12, 32, 32]}
              rotation={[frame * 0.002, frame * 0.005, frame * 0.001]}
              scale={[scaleB, scaleB, scaleB]}
            >
              <meshBasicMaterial
                color={theme.colors.warning}
                wireframe={true}
                transparent={true}
                opacity={opacityB}
              />
            </Sphere>
          </group>
        </FullCanvas>
      </AbsoluteFill>

      {/* 2D UI Layer */}
      <SafeArea padding={60} paddingBottom={160} style={{ zIndex: 1 }}>
        <div
