      "import React, { useMemo } from "react";
import {
  AbsoluteFill,
  useCurrentFrame,
  useVideoConfig,
  interpolate,
  spring,
  random,
} from "remotion";
import { SafeArea, Subtitle, SafeIcon } from "../components";
import { useTheme } from "../contexts/ThemeContext";

// --- Helper Components for Glitch Effect ---

/**
 * Generates a random horizontal slice clip-path for the glitch effect.
 */
const getGlitchClipPath = (seed: string, frame: number, intensity: number) => {
  if (intensity <= 0) return "none";
  const y = random(`${seed}-y-${frame}`) * 100;
  const h = random(`${seed}-h-${frame}`) * 40 * intensity; // Max 40% height slice
  const bottomInset = Math.max(0, 100 - y - h);
  return `inset(${y}% 0 ${bottomInset}% 0)`;
};

/**
 * A wrapper that applies an RGB-split and slicing glitch effect to its children.
 */
const GlitchWrapper: React.FC<{
  children: React.ReactNode;
  intensity: number;
  seed: string;
  frame: number;
  theme: any;
}> = ({ children, intensity, seed, frame, theme }) => {
  if (intensity <= 0) {
    return <>{children}</>;
  }

  // Calculate random offsets based on intensity
  const maxOffset = 30;
  const rX1 = (random(`${seed}-rx1-${frame}`) - 0.5) * maxOffset * intensity;
  const rY1 = (random(`${seed}-ry1-${frame}`) - 0.5) * 10 * intensity;
  const rX2 = (random(`${seed}-rx2-${frame}`) - 0.5) * maxOffset * intensity;
  const rY2 = (random(`${seed}-ry2-${frame}`) - 0.5) * 10 * intensity;

  const clip1 = getGlitchClipPath(`${seed}-c1`, frame, intensity);
  const clip2 = getGlitchClipPath(`${seed}-c2`, frame, intensity);

  // Base jitter for the main element
  const baseX = (random(`${seed}-bx-${frame}`) - 0.5) * 10 * intensity;
  const baseY = (random(`${seed}-by-${frame}`) - 0.5) * 10 * intensity;

  return (
    <div style={{ position: "relative", width: "100%", height: "100%" }}>
      {/* Cyan Channel (Primary) */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          transform: `translate(${rX1}px, ${rY1}px)`,
          clipPath: clip1,
          color: theme.colors.primary,
          opacity: 0.8,
          mixBlendMode: "screen",
          pointerEvents: "none",
          filter: `drop-shadow(0 0 8px ${theme.colors.primary})`,
        }}
      >
        {children}
      </div>

      {/* Red Channel (Accent) */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          transform: `translate(${rX2}px, ${rY2}px)`,
          clipPath: clip2,
          color: theme.colors.accent,
          opacity: 0.8,
          mixBlendMode: "screen",
