            "import React, { useMemo, useRef } from "react";
import { AbsoluteFill, useCurrentFrame, useVideoConfig, interpolate, Easing } from "remotion";
import { FullCanvas, SafeArea, Subtitle, SafeIcon } from "../components";
import { useTheme } from "../contexts/ThemeContext";
import * as THREE from "three";
import { Line, PerspectiveCamera, Float, Text, Billboard, Environment, Trail, useCursor } from "@react-three/drei";
import { useFrame } from "@react-three/fiber";

// --- 3D Components ---

const Ship = ({ color, position, rotation }: { color: string; position: THREE.Vector3; rotation: THREE.Euler }) => {
  return (
    <group position={position} rotation={rotation}>
      {/* Wake Effect using Trail */}
      <Trail
        width={1.5}
        length={12}
        color="#ffffff"
        attenuation={(t) => t * t}
        target={undefined} // Fix for TS optional prop
      >
        {/* Hull */}
        <mesh position={[0, 0.5, 0]} castShadow receiveShadow>
          <boxGeometry args={[1, 1, 4]} />
          <meshStandardMaterial color="#cccccc" roughness={0.3} metalness={0.8} />
        </mesh>
      </Trail>

      {/* Bow */}
      <mesh position={[0, 0.5, 2.5]} rotation={[Math.PI / 2, 0, 0]} castShadow receiveShadow>
        <coneGeometry args={[0.7, 1.5, 4]} />
        <meshStandardMaterial color="#cccccc" roughness={0.3} metalness={0.8} />
      </mesh>
      {/* Bridge */}
      <mesh position={[0, 1.5, -1]} castShadow receiveShadow>
        <boxGeometry args={[1.2, 1, 1]} />
        <meshStandardMaterial color={color} roughness={0.2} metalness={0.5} />
      </mesh>
      {/* Chimney */}
      <mesh position={[0, 2.2, -1.2]} castShadow>
        <cylinderGeometry args={[0.2, 0.2, 0.8]} />
        <meshStandardMaterial color="#333" />
      </mesh>

      {/* Port/Starboard Lights */}
      <mesh position={[0.6, 1, 1]}>
        <boxGeometry args={[0.1, 0.1, 0.1]} />
        <meshBasicMaterial color="#00ff00" />
      </mesh>
      <mesh position={[-0.6, 1, 1]}>
        <boxGeometry args={[0.1, 0.1, 0.1]} />
        <meshBasicMaterial color="#ff0000" />
      </mesh>
    </group>
  );
};

const Ocean = () => {
  const ref = useRef<THREE.Mesh>(null);

  useFrame(({ clock }) => {
    if (ref.current) {
      // Simple wave animation by bobbing the plane
      ref.current.position.y = Math.sin(clock.getElapsedTime() * 0.5) * 0.2 - 0.2;
    }
  });

  return (
    <mesh ref={ref} rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.2, 0]} receiveShadow>
      <planeGeometry args={[200, 200, 32, 32]} />
      <meshStandardMaterial 
        color="#102a45" 
        roughness={0.1} 
        metalness={0.5}
        transparent
        opacity={0.9}
      />
      <gridHelper args={[200, 40, 0xffffff, 0xffffff]} position={[0, 0.05, 0]} rotation={[Math.PI/2, 0, 0]} />
    </mesh>
  );
};

// Dynamic Camera Follower
const CameraController = ({ target }: { target: THREE.Vector3 }) => {
  useFrame((state) => {
    // Offset camera relative to ship position
    const offset = new THREE.Vector3(15, 25, 20);
    const desiredPosition = target.clone().add(offset);

    // Direct assignment for deterministic rendering (avoid lerp accumulation issues in seek)
    state.camera.position.copy(desiredPosition);
    state.camera.lookAt(target);
  });
  return null;
};

// --- UI Components ---

const RudderIndicator = ({ angle, theme }: { angle: number; theme: any }) => {
  // angle: -35 (Left) to 35 (Right)
  const rotation = interpolate(angle, [-35, 35], [-45, 45], { extrapolateRight: "clamp", extrapolateLeft: "clamp" });

  return (
    <div style={{
      position: 'absolute',
      bottom: 180,
      right: 40,
