        width: 4,
        height: 50,
        background: theme.colors.primary,
        transformOrigin: 'bottom center',
        transform: `rotate(${rotation}deg)`,
        transition: 'transform 0.1s linear'
      }} />
      <div style={{ position: 'absolute', bottom: 5, fontSize: 12, color: 'white', fontFamily: theme.fonts.mono }}>
        {Math.abs(Math.round(angle))}° {angle < 0 ? 'PORT' : angle > 0 ? 'STBD' : 'MID'}
      </div>
    </div>
  );
};

const Compass = ({ heading, theme }: { heading: number; theme: any }) => {
  return (
