          <line x1="50" y1="85" x2="50" y2="95" stroke="white" strokeWidth="1" />
          <line x1="95" y1="50" x2="85" y2="50" stroke="white" strokeWidth="1" />
          <line x1="5" y1="50" x2="15" y2="50" stroke="white" strokeWidth="1" />
