export default function Scene2() {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const theme = useTheme();

  const durationInFrames = 35 * fps;

  // Subtitles
  const subtitles = [
    { 
      text: "发现落水者，立即向落水者一侧操满舵 (Hard Starboard)", 
      start_time_seconds: 0, 
      end_time_seconds: 10 
    },
    { 
      text: "航向偏离 60 度后，立即操另一侧满舵 (Hard Port)", 
      start_time_seconds: 10.5, 
      end_time_seconds: 22 
    },
    { 
      text: "保持满舵，直到船首驶上反航向 (Reciprocal Course)", 
      start_time_seconds: 22.5, 
      end_time_seconds: 35 
    }
  ];

  // Curve Definition
  const curve = useMemo(() => {
    return new THREE.CatmullRomCurve3([
      new THREE.Vector3(0, 0, 20),    // Start
      new THREE.Vector3(0, 0, 10),    // Incident
      new THREE.Vector3(2, 0, 5),     // Turn Start
      new THREE.Vector3(8, 0, 0),     // 60 deg area
      new THREE.Vector3(12, 0, -5),   // Apex
      new THREE.Vector3(8, 0, -10),   // Return
      new THREE.Vector3(4, 0, -12),   // Align
      new THREE.Vector3(4, 0, -20),   // End
    ], false, 'catmullrom', 0.2);
  }, []);

  // Motion Calculations
  const progress = interpolate(frame, [0, durationInFrames], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp"
  });

  const shipPosition = curve.getPoint(progress);
  const tangent = curve.getTangent(progress).normalize();
  const angle = Math.atan2(tangent.x, tangent.z);
  const shipRotation = new THREE.Euler(0, angle, 0);

  // Heading & Deviation
  const initialAngle = Math.PI; // Roughly South
  let deviationDeg = Math.abs((angle - initialAngle) * (180 / Math.PI));
  if (deviationDeg > 180) deviationDeg = 360 - deviationDeg;

  // True Heading (0-360) for Compass
  // angle is in radians, 0 is South (+Z) in Three.js standard? 
  // Actually atan2(x, z): 0 is +Z (South), PI is -Z (North). 
  // Let's normalize to degrees 0-360.
  let headingDeg = (angle * 180 / Math.PI);
  if (headingDeg < 0) headingDeg += 360;

  // Logic Triggers
  const is60DegReached = deviationDeg >= 60;
  const turnPointTime = 10.5 * fps; // Time to switch rudder

  // Rudder Animation
  // 0-10s: +35 (Starboard), >10.5s: -35 (Port)
  const rudderTarget = frame < turnPointTime ? 35 : -35;
  // Smooth the rudder movement
  const rudderAngle = interpolate(
    frame, 
    [turnPointTime - 15, turnPointTime + 15], 
    [35, -35], 
    { easing: Easing.inOut(Easing.cubic), extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );

  // Trail points for path visualization
  const trailPoints = useMemo(() => curve.getPoints(100), [curve]);
  const visibleTrailPoints = useMemo(() => {
    const count = Math.floor(progress * 100);
    return trailPoints.slice(0, Math.max(2, count));
  }, [progress, trailPoints]);

  return (
    <AbsoluteFill style={{ background: theme.colors.background }}>

      {/* 3D Scene */}
      <FullCanvas shadows>
        <CameraController target={shipPosition} />

        {/* Environment & Lighting */}
        <Environment preset="sunset" blur={0.6} />
        <ambientLight intensity={0.4} />
        <directionalLight 
          position={[50, 50, 20]} 
          intensity={1.5} 
          castShadow 
          shadow-mapSize={[1024, 1024]} 
        />

        <Ocean />

        {/* The Ship */}
        <Float speed={2} rotationIntensity={0.05} floatIntensity={0.1}>
          <Ship 
            color={theme.colors.primary} 
            position={shipPosition} 
            rotation={shipRotation} 
          />
        </Float>

        {/* 3D Labels */}
        <Billboard position={[shipPosition.x, shipPosition.y + 5, shipPosition.z]}>
          <Text
            fontSize={2}
            color={is60DegReached ? "#FFD700" : "white"}
            anchorY="bottom"
            outlineWidth={0.1}
            outlineColor="#000000"
          >
            {Math.round(deviationDeg)}° Dev
          </Text>
          {is60DegReached && frame < 22 * fps && (
            <Text
              position={[0, -1.2, 0]}
              fontSize={1.2}
              color="#FF4444"
              anchorY="top"
              outlineWidth={0.05}
              outlineColor="#000000"
            >
              COUNTER RUDDER!
            </Text>
          )}
        </Billboard>

        {/* Path Lines */}
        <Line
          points={trailPoints}
          color="rgba(255, 255, 255, 0.1)"
          lineWidth={1}
          dashed
          dashScale={2}
        />
        <Line
          points={visibleTrailPoints}
          color={theme.colors.primary}
          lineWidth={3}
        />

        {/* Incident Marker */}
        <mesh position={[0, 0.1, 10]}>
          <ringGeometry args={[0.5, 0.7, 32]} />
          <meshBasicMaterial color="#ff3333" side={THREE.DoubleSide} />
        </mesh>
      </FullCanvas>

      {/* Critical Event Visual Feedback (Red Flash) */}
      {is60DegReached && frame < (turnPointTime + 30) && (
        <AbsoluteFill style={{ 
          boxShadow: 'inset 0 0 100px rgba(255, 0, 0, 0.3)', 
          pointerEvents: 'none',
          zIndex: 10
        }} />
      )}

      {/* UI Overlay */}
      <SafeArea padding={40} style={{ pointerEvents: 'none' }}>
        {/* Header */}
        <div style={{ 
          display: 'flex', 
          alignItems: 'center', 
          gap: 20, 
          color: 'white' 
        }}>
          <Compass heading={headingDeg} theme={theme} />
          <div>
            <h2 style={{ 
              margin: 0, 
              fontSize: 32, 
              fontFamily: theme.fonts.heading,
              textShadow: '0 2px 4px rgba(0,0,0,0.5)'
            }}>
              Williamson Turn
            </h2>
            <div style={{ 
              display: 'flex', 
              gap: 12, 
              marginTop: 8, 
              fontFamily: theme.fonts.mono,
              fontSize: 16,
              opacity: 0.9
            }}>
              <div style={{ 
                padding: '4px 8px', 
                background: is60DegReached ? 'rgba(255,68,68,0.3)' : 'rgba(255,255,255,0.1)',
                borderRadius: 4,
                border: is60DegReached ? '1px solid #ff4444' : '1px solid rgba(255,255,255,0.2)'
              }}>
