                strokeWidth="8" 
                fill="none"
                strokeLinecap="round"
                strokeDasharray={totalLength}
                strokeDashoffset={drawProgress}
                markerEnd="url(#arrow-head)"
                filter="url(#glow)"
              />

              {/* Phase 1: Incident Point Label */}
              <g transform="translate(960, 600)" opacity={opacityLabel1}>
                <circle r="10" fill="#ef4444" stroke="white" strokeWidth="2" />
