const Ocean = () => {
  const meshRef = useRef<THREE.Mesh>(null);

  useFrame(({ clock }) => {
    if (meshRef.current) {
      meshRef.current.position.y = Math.sin(clock.getElapsedTime()) * 0.2 - 1;
    }
  });

  return (
    <Plane args={[100, 100]} rotation={[-Math.PI / 2, 0, 0]} position={[0, -1, 0]}>
      <meshStandardMaterial color="#004978" roughness={0.1} metalness={0.1} />
    </Plane>
  );
};

const RescueBoat = () => {
  const groupRef = useRef<THREE.Group>(null);

  useFrame(({ clock }) => {
    if (groupRef.current) {
      groupRef.current.position.y = Math.sin(clock.getElapsedTime() * 2) * 0.1;
      groupRef.current.rotation.z = Math.sin(clock.getElapsedTime() * 1.5) * 0.05;
    }
  });

  return (
    <group ref={groupRef} position={[-2, 0, 0]}>
      <Box args={[3, 1, 1.5]} position={[0, 0, 0]}>
        <meshStandardMaterial color="#ffffff" />
      </Box>
      <Box args={[1, 1, 1]} position={[-0.5, 1, 0]}>
