  const ref = useRef<THREE.Group>(null);

  useFrame(({ clock }) => {
    if (ref.current) {
      const t = clock.getElapsedTime();
      ref.current.position.x = 2 + t * 0.1;
      ref.current.position.z = t * 0.05;
      ref.current.position.y = Math.sin(t * 3) * 0.1;
