              // 错峰显示动画
              const delay = 40 + i * 30;
              const qOpacity = interpolate(frame, [delay, delay + 20], [0, 1], { extrapolateRight: "clamp" });
              const qX = interpolate(frame, [delay, delay + 20], [-20, 0], { extrapolateRight: "clamp" });

              return (
                <div 
                  key={i} 
                  style={{ 
                    opacity: qOpacity, 
                    transform: `translateX(${qX}px)`,
                    fontSize: 42,
                    fontFamily: theme.fonts.body,
                    color: theme.colors.text,
                    background: `${theme.colors.surface}40`,
                    padding: "20px 32px",
