                  }}
                >
                  {q}
                </div>
              );
            })}
          </div>

          {/* 底部感谢语 */}
          <div 
            style={{ 
              marginTop: 80, 
              opacity: footerOpacity,
              borderTop: `1px solid ${theme.colors.textSecondary}40`,
              paddingTop: 32
            }}
          >
