              fontFamily: theme.fonts.body, 
              fontSize: 32, 
              color: theme.colors.textSecondary, 
              margin: 0 
            }}>
              感谢观看，请按实训要求完成操纵模拟
            </p>
          </div>
        </div>
      </SafeArea>

      {/* 字幕层 */}
      {subtitles.map((s, i) => (
        <Subtitle 
          key={i}
          text={s.text}
          startFrame={Math.round(s.start_time_seconds * fps)}
          durationInFrames={Math.round((s.end_time_seconds - s.start_time_seconds) * fps)}
        />
      ))}
    </AbsoluteFill>
